INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-c5fb3965-moex-00121', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「處理報導內容的重要區塊時，記者要像嚮導一樣。他提出門外漢都會做 的謹慎結論，但也必須列出一些證據來佐證那些結論。如果沒有證據，文 章會顯得自以為是，空洞不實。不過，在文章的邊緣區塊，記者不再只是 嚮導，他可以利用讀者賦予的代理權，為讀者提供臨場感及人物的實感。」 根據上文，下列選項最符合文意的是：', '["記者報導應該致力突破文章邊界，爭取讀者代理權", "報導以詳細證據輔助結論，並從讀者角度強化感受", "新聞報導通常只會給出常人可知的結論，以免犯錯", "新聞報導追求臨場感與人物實感，反而削減證據力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00122', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「AI的本質是去取代人的腦力，也就是所謂的專家智慧；而法律的本質， 不純粹是追求價值觀的維護，而更傾向是經濟、政治、科技改變下的產物。 在可預見的未來，AI技術即將衝擊到法律的解釋適用，而當社會進一步受 到 AI 衝擊後，應運而生的將是許多因應 AI 的修法，如 AI 篩選面試者的 機制可能造成的歧視、隱私權問題。」 下列敘述何者正確？', '["AI智慧將會完全取代專家", "AI科技不會衝擊人文法律", "AI的本質是追求絕對價值", "AI執行仍須專家整合思考"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00123', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「聯合國在2022年發布的2023人口報告中就警告，所有國家都需要為人 口老化的現實做好準備。因為社會與經濟的衰老與停滯是大多數富裕國家 與中等收入國家被迫面對的共同難題。生存狀況顯著改善與生育率下降， 已經讓人口老化成為這個時代不可逆轉的全球趨勢，越晚面對人口老化問 題，所要負擔的社會、經濟、財政和衛生成本將越高昂。」 根據上文，關於人口老化的原因，下列推論何者正確？', '["富裕與中等收入國家的政策是造成人口老化的原因", "經濟不斷衰退，造成人口老化，這是目前全球所面臨的難題", "因為衛生成本逐年增加，導致經濟停滯，間接影響國家的生存狀況", "生育率下降與生存狀況的改善，讓人口老化成為全球共同面臨的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00124', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「臺灣森林分為天然林與人工林，目前天然林因保育而全面禁伐，但人工 林則否。在世界提倡淨碳排的趨勢下，森林『碳匯』議題越來越被重視—— 意即森林具有固碳功能，可以將二氧化碳吸存固著於自然環境中，形成如 同把錢存在銀行一樣的倉庫。因此，要增加碳匯，就必須多造林。然而， 樹木會老化，過了 20 年的生長巔峰期，固碳能力逐年下降，最後失去固 碳功能，是以人工林的更新有其必要性。」 根據上文，下列選項最符合文意的是：', '["樹齡越大、枝葉越茂盛，對環境保護的效益越大", "人工林的造林和定期採伐，有其實質上的必要性", "環境意識的崛起，禁伐已是全球山林保育的趨勢", "天然林比人工林更具有碳匯的效益，可增加獲利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00125', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '某企業代表在產業高峰會中表示：「為了能招募外國人才，加上臺灣環境 資源有限，包括土地、水、電，走出臺灣是不得不做的事情。然而在海外 布局的過程面臨兩個挑戰，首先是全球人才不足，不僅人口變少，念半導 體的人也變少。另一個挑戰是文化融合，應以開放心態因應。全球化布局 可能造成成本增加，增加的成本是由客戶吸收，或企業自行吸收，將會是 挑戰，也是企業全球化要面對的議題。」 根據上文，下列選項何者正確？', '["產業發展必須倚賴全球人才，但也要考慮文化融合的衝擊", "受新冠肺炎疫情影響，人才流動受限，因此必須走出臺灣", "為了產品標準化，應該統一各地製程、管理、營運之步驟", "全球布局能利用各地廉價的勞工、土地、水電，降低成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00126', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「一葉知秋，一根頭髮可以讓罪犯無所遁形。可見，頭髮就是人這棵樹的 葉子。秋天到了，葉轉黃，年紀大了，髮變白。人與時間拔河，以白髮為 繩。老，本是自然律裡的事，擋不了也無須擋。一派天真自然，反而能使 『老』這件事顯出美好的部分。我不討厭白髮，有時還覺得有些人的白髮 長得真好看。如果一棵樹的葉子綠得像幫派，看久了會膩，若泛起霜紅色 澤，美就來了。人亦如此，渾身上下要一起老才好。白髮是落雪天氣，人 生走到這一步，離暴動份子的時代遠了，較接近沉思的智者。」 根據上文，下列選項何者最符合文意？', '["活到老，學到老", "老吾老，以及人之老", "夕陽無限好，正是近黃昏", "人間只道黃金貴，不問天公買少年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00127', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「人天生就有建築的本能。《高塔，一種□□□□的建築》一書中，描述 一個事業受挫、婚姻失敗的中年人，自己到野外湖濱建造高塔的過程。雖 然不是建築科班出身，但他受到內心本能的驅使，開始在湖邊建造一座高 塔。過程中，他感受到內心的沉澱與改變。等到高塔建造完成，他似乎得 到了某種力量，又可以重新去面對自己不完美的人生。」 根據文意，最適合填入□□□□，用以描述文中高塔特質的選項是：', '["隨心所欲", "自我療癒", "挑戰極限", "睥睨天下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00128', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列關於戶籍之敘述，何者正確？', '["戶籍登記，以家為單位", "一人同時不得有二戶籍", "在同一家或同一處所共同生活之普通住戶為共同事業戶", "在同一處所同一主管人之下經營共同事業之工廠、商店、寺廟者為共同 生活戶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00129', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列何者非屬戶籍登記？', '["出生登記", "出生地登記", "死亡登記", "繼承登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00130', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '戶籍法第4條規定之登記事項，不包括下列何者？', '["死亡", "結婚", "預立醫療決定書", "未成年子女權利義務行使負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
